INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-6f0ba476-moex-00160', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲男與乙女結婚，育有一女6歲之丙，但因個性不合離婚，由乙對丙行使親權。其後乙認識丁， 丁對丙疼愛有加，丁經乙同意後，擬收養丙，向法院聲請認可。下列敘述，何者正確？', '["甲、乙離婚，乙取得親權，已可自行決定，丁收養丙，無須甲之同意", "甲、乙雖然離婚，但仍應經甲之同意，始得收養丙", "法院認可丙丁之收養契約時，無須考量丙之最佳利益", "丁收養丙必須與乙共同收養"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00161', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '甲於其父乙死亡後，傷心過度旋即死亡。乙死亡時未有配偶，遺有財產新臺幣（下同）1,200萬元， 甲另有同父異母姐姐丁。甲之子戊及女己，各得繼承多少財產？', '["300萬元", "400萬元", "600萬元", "不得繼承"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00162', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9b7ab1bb', 'sub-aboriginal-6f0ba476-02', NULL, 'single_choice', '下列何者得以遺囑指定應繼分？', '["滿14歲得法定代理人同意之未成年人", "18歲因酒醉無意識能力之人", "滿25歲受監護宣告之人", "滿30歲受輔助宣告之人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:53+00:00", "source_pdf_sha1": "039c851c4821", "answer_pdf_sha1": "f483a53fcf7d", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "0801", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00163', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'essay', '某甲 112 年在新竹市共持有 6筆都市土地，每筆土地面積均為 1公畝，
每筆土地的相關資料如下表所示，假設新竹市之累進起點地價為100 萬
元，請依土地稅法、土地稅法施行細則回答下列問題：
何謂自用住宅用地？又適用自用住宅用地優惠稅率之條件為何？（15分）
某甲那幾塊土地適用自用住宅用地優惠稅率？又112年之地價稅稅額
為若干？（10 分）
土地 課稅地價總額 設籍者 建物所有權人 是否出租或營業用
A 100萬 某甲 某甲配偶 否
B 100萬 某甲配偶 某甲 否
C 100萬 某甲已成年兒子 某甲 否
D 200萬 某甲未成年女兒 某甲父親 否
E 200萬 某甲父親 某甲弟弟 是
F 200萬 某甲岳父 某甲岳父 否', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00164', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'essay', '何謂小規模營利事業？若甲店家為中華民國境內之獨資的小規模營利
事業，112年度核定之營利事業所得額為 20萬元，負責人（資本主）林
小姐為中華民國境內居住之個人，請依稅法規定說明林小姐該如何計算
繳納 112 年度之綜合所得稅、營利事業所得稅及營業稅？（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00165', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，有關稽徵機關實施租稅保全措施，下列敘述何者正確？', '["納稅義務人欠繳應納稅捐，已提供相當擔保者，稽徵機關應通知有關機關，不得為移轉或設定 他項權利", "營利事業欠繳應納稅捐，已提供相當擔保者，稽徵機關得於法定繳納期間屆滿後聲請假扣押", "中華民國境內居住之個人欠繳已確定之應納稅捐及罰鍰，如未提起行政救濟者，單計或合計達 新臺幣50萬元以上者，得予限制出境", "在中華民國境內之營利事業，欠繳在行政救濟程序終結前之應納稅捐及已確定之罰鍰達新臺幣 300萬元者，得限制負責人出境"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00166', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '依納稅者權利保護法之規定，下列敘述何者正確？', '["納稅者權利保護法之中央主管機關為經濟部", "納稅者權利保護諮詢會的任務之一為受理納稅者之申訴或陳情，並提出改善建議", "納稅者權利保護官的職責之一為協助納稅者進行稅捐爭議之溝通與協調", "稅捐稽徵機關對於課稅基礎，經調查仍不能確定或調查費用過鉅時，基於維護租稅中立性，得 採推計課稅方式計稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00167', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '某甲於113年5月初收到113年度房屋稅繳款書，繳納截止日期為113年5月31日（週五），某 甲並未申請展延，且遲至113年6月12日（週三）繳納房屋稅款5 萬元，請問應加徵多少滯納 金？', '["3,000元", "2,500元", "2,000元", "1,500元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00168', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '下列受益人受領之保險給付，何者屬個人基本所得額應計入項目？', '["民國93年簽訂之要保人不等於受益人之年金保險契約", "民國103年簽訂之要保人不等於受益人之健康保險契約", "民國96年簽訂之要保人不等於受益人之人壽保險契約", "民國98年簽訂之要保人等於受益人之年金保險契約"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('aboriginal-6f0ba476-moex-00169', 'aboriginal-6f0ba476', 'aboriginal-6f0ba476-moex-113-9bdab6d6', 'sub-aboriginal-6f0ba476-03', NULL, 'single_choice', '張小姐於113年6月30日退休，服務年資為20年，張小姐選擇一次領取退休金560萬元，財政 部公告113年退職所得之所得額為零及以半數為所得額計算之參數，分別為19.8萬元及39.8萬 元，請問張小姐之退休金有多少免稅？', '["796萬元", "560萬元", "478萬元", "396萬元"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:54+00:00", "source_pdf_sha1": "c9123be7d2a8", "answer_pdf_sha1": "c0018f096be7", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "407", "s": "1202", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "財稅行政"}'::jsonb, NULL)
